import os, sys
import base64
import io
from pathlib import Path
from datetime import datetime

import pandas as pd
from reportlab.lib.units import inch
from reportlab.lib import colors
from reportlab.pdfgen import canvas as pdf_canvas
from reportlab.lib.utils import ImageReader

# ─────────────────────────────────────────────────────────────────
#  PATHS & EMBEDDED LOGO (UPDATED FOR ROOT ARCHITECTURE ENVIRONMENT)
# ─────────────────────────────────────────────────────────────────
# Script lives in 'PY Files' sub-folder
BASE_DIR   = Path(__file__).parent
# Root directory is one level up
ROOT_DIR   = BASE_DIR.parent

LOGO_FILE  = BASE_DIR / "lunch_lady_logo.png"
# Targets the 'PDF Labels' folder in the root directory
OUTPUT_DIR = ROOT_DIR / "PDF Labels"

# ⬇️ STEP 2 DIRECTIONS: Paste your long text string inside these triple quotes!
# Once pasted, you can delete 'lunch_lady_logo.png' forever.
LOGO_BASE64 = """

"""

# Automatic asset extractor helper
if LOGO_FILE.exists():
    try:
        with open(LOGO_FILE, "rb") as image_file:
            encoded_string = base64.b64encode(image_file.read()).decode('utf-8')

        txt_out = BASE_DIR / "READY_TO_COPY_LOGO.txt"
        if not txt_out.exists():
            with open(txt_out, "w") as text_file:
                text_file.write(encoded_string)
    except Exception:
        pass

# Find the Excel template workbook out of the root directory path
def find_excel():
    for pat in ("Lunch Lady Template.xlsx", "*.xlsm", "*.xlsx"):
        files = sorted(ROOT_DIR.glob(pat))
        if files:
            return files[0]
    return None

# ─────────────────────────────────────────────────────────────────
#  PAGE & LABEL DIMENSIONS
# ─────────────────────────────────────────────────────────────────
PAGE_W   = 8.5  * inch    # portrait letter
PAGE_H   = 11.0 * inch
MARGIN_X = 0.22 * inch    # left / right page margin
MARGIN_Y = 0.25 * inch    # top / bottom page margin
GAP_X    = 0.16 * inch    # horizontal gap between the 2 label columns
GAP_Y    = 0.10 * inch    # vertical gap between label rows
LABEL_H  = 2.0  * inch    # fixed label height (4"×2" MUNBYN)
COLS     = 2              # 2 labels side-by-side

# Computed label width  (fills the usable width exactly in 2 columns)
LABEL_W  = (PAGE_W - 2 * MARGIN_X - GAP_X) / COLS   # ≈ 3.93"
ROWS_PP  = int((PAGE_H - 2 * MARGIN_Y + GAP_Y) / (LABEL_H + GAP_Y))  # rows per page

# ─────────────────────────────────────────────────────────────────
#  COLOURS
# ─────────────────────────────────────────────────────────────────
C_BLACK      = colors.black
C_WHITE      = colors.white
C_DARK_GREY  = colors.HexColor('#333333')
C_MID_GREY   = colors.HexColor('#888888')
C_RULE       = colors.HexColor('#444444')
C_DASH       = colors.HexColor('#999999')
C_ALLERGY_R  = colors.HexColor('#D32F2F')
C_ALLERGY_BG = colors.HexColor('#EEEEEE')
C_BORDER     = colors.HexColor('#AAAAAA')


# ─────────────────────────────────────────────────────────────────
#  DATA LOADING
# ─────────────────────────────────────────────────────────────────
def load_orders(excel_path: Path):
    raw = pd.read_excel(str(excel_path),
                        sheet_name='Daily_Packing',
                        engine='openpyxl',
                        header=None)

    date_val = raw.iloc[0, 2]
    if pd.isna(date_val):
        raise ValueError(
            "Date not found in Daily_Packing cell C1.\n"
            "Please set the date in the Daily_Packing sheet and save the file.")
    svc_date = pd.to_datetime(date_val)

    headers = raw.iloc[2].tolist()
    col_map = {}
    for i, h in enumerate(headers):
        if not isinstance(h, str):
            continue
        hl = h.strip().lower()
        if   'student'  in hl: col_map['student']   = i
        elif 'school'   in hl: col_map['school']    = i
        elif 'class'    in hl: col_map['classroom'] = i
        elif 'allerg'   in hl: col_map['allergy']   = i
        elif 'entree'   in hl: col_map['entree']    = i
        elif 'side 1'   in hl: col_map['side1']     = i
        elif 'side 2'   in hl: col_map['side2']     = i

    def get(row, key):
        idx = col_map.get(key)
        if idx is None:
            return ''
        v = row.iloc[idx]
        return '' if pd.isna(v) else str(v).strip()

    orders = []
    for _, row in raw.iloc[3:].iterrows():
        student = get(row, 'student')
        if not student:
            continue

        allergy_raw = get(row, 'allergy')
        allergy = ('' if allergy_raw.lower() in ('no', 'no.', 'none', '')
                   else allergy_raw.upper())

        orders.append({
            'student':   student.upper(),
            'school':    get(row, 'school').upper(),
            'classroom': get(row, 'classroom').upper(),
            'allergy':   allergy,
            'entree':    get(row, 'entree').upper(),
            'side1':     get(row, 'side1').upper(),
            'side2':     get(row, 'side2').upper(),
        })

    orders.sort(key=lambda x: (x['school'], x['classroom'], x['student']))
    return svc_date, orders


# ─────────────────────────────────────────────────────────────────
#  DRAW ONE LABEL
# ─────────────────────────────────────────────────────────────────
def draw_label(c: pdf_canvas.Canvas, lx: float, ly: float,
               order: dict, date_str: str, logo):
    W = LABEL_W
    H = LABEL_H

    c.saveState()

    c.setStrokeColor(C_BORDER)
    c.setLineWidth(0.8)
    c.roundRect(lx, ly, W, H, 0.1 * inch, stroke=1, fill=0)

    clip = c.beginPath()
    clip.roundRect(lx, ly, W, H, 0.1 * inch)
    c.clipPath(clip, stroke=0, fill=0)

    logo_size = 0.44 * inch
    logo_x = lx + W / 2 - logo_size / 2
    logo_y = ly + H - 0.03 * inch - logo_size
    if logo:
        c.drawImage(logo, logo_x, logo_y,
                    width=logo_size, height=logo_size,
                    preserveAspectRatio=True, mask='auto')

    cur_y = logo_y - 0.01 * inch

    c.setStrokeColor(C_RULE)
    c.setLineWidth(0.5)
    rule_pad = 0.52 * inch
    c.line(lx + rule_pad, cur_y, lx + W - rule_pad, cur_y)
    c.setFillColor(C_RULE)
    c.circle(lx + W / 2, cur_y, 1.3, fill=1, stroke=0)
    cur_y -= 0.01 * inch

    cur_y -= 0.105 * inch
    c.setFont('Helvetica-Bold', 6.8)
    c.setFillColor(C_DARK_GREY)
    c.drawCentredString(lx + W / 2, cur_y, f'DATE: {date_str.upper()}')

    name = order['student']
    fs = 15 if len(name) <= 18 else (12 if len(name) <= 24 else 10)
    c.setFont('Helvetica-Bold', fs)
    c.setFillColor(C_BLACK)
    cur_y -= (fs / 72 * inch) + 0.015 * inch
    c.drawCentredString(lx + W / 2, cur_y, name)

    c.setFont('Helvetica-Bold', 5.8)
    c.setFillColor(C_DARK_GREY)
    cur_y -= 0.118 * inch
    c.drawCentredString(lx + W / 2, cur_y, f'SCHOOL: {order["school"]}')

    cur_y -= 0.108 * inch
    c.drawCentredString(lx + W / 2, cur_y, f'TEACHER: {order["classroom"]}')
    cur_y -= 0.02 * inch

    cur_y -= 0.042 * inch
    c.setStrokeColor(C_DASH)
    c.setLineWidth(0.4)
    c.setDash(2, 3)
    c.line(lx + 0.1 * inch, cur_y, lx + W - 0.1 * inch, cur_y)
    c.setDash()
    cur_y -= 0.018 * inch

    cur_y -= 0.108 * inch
    c.setFont('Helvetica-Bold', 6.8)
    c.setFillColor(C_BLACK)
    c.drawCentredString(lx + W / 2, cur_y, f'ENTREE: {order["entree"]}')

    cur_y -= 0.1 * inch
    c.setFont('Helvetica', 6.5)
    c.setFillColor(C_DARK_GREY)
    c.drawCentredString(lx + W / 2, cur_y, f'SIDE 1: {order["side1"]}')

    cur_y -= 0.095 * inch
    side2_txt = order['side2'] if order['side2'] else '—'
    c.drawCentredString(lx + W / 2, cur_y, f'SIDE 2: {side2_txt}')

    bar_h = 0.175 * inch
    if order['allergy']:
        c.setFillColor(C_ALLERGY_R)
        c.rect(lx, ly, W, bar_h, fill=1, stroke=0)
        c.setFont('Helvetica-Bold', 7.5)
        c.setFillColor(C_WHITE)
        c.drawCentredString(lx + W / 2, ly + 0.052 * inch,
                            f'\u26a0  ALLERGY: {order["allergy"]}  \u26a0')
    else:
        c.setFillColor(C_ALLERGY_BG)
        c.rect(lx, ly, W, bar_h, fill=1, stroke=0)
        c.setFont('Helvetica', 6.5)
        c.setFillColor(C_MID_GREY)
        c.drawCentredString(lx + W / 2, ly + 0.052 * inch, 'ALLERGY: NONE')

    c.restoreState()


# ─────────────────────────────────────────────────────────────────
#  PDF GENERATION
# ─────────────────────────────────────────────────────────────────
def generate_pdf(orders, svc_date, out_path: Path):
    ds = svc_date.strftime('%B %d, %Y')
    day = str(svc_date.day)
    date_str = svc_date.strftime('%B ') + day + svc_date.strftime(', %Y')

    # Load logo: Try direct image first, fallback to embedded string
    logo = None
    if LOGO_FILE.exists():
        try:
            logo = ImageReader(str(LOGO_FILE))
        except Exception:
            pass

    if logo is None and LOGO_BASE64.strip() and "PASTE_YOUR_BASE64_TEXT_HERE" not in LOGO_BASE64:
        try:
            img_data = base64.b64decode(LOGO_BASE64.strip())
            logo = ImageReader(io.BytesIO(img_data))
        except Exception as e:
            print(f'  ⚠ Logo text string failed to parse: {e}')

    c = pdf_canvas.Canvas(str(out_path), pagesize=(PAGE_W, PAGE_H))
    c.setTitle(f'Lunch Lady Labels — {date_str}')

    current_page = 0

    for idx, order in enumerate(orders):
        col        = idx % COLS
        row_on_pg  = (idx // COLS) % ROWS_PP
        page_idx   = (idx // COLS) // ROWS_PP

        if page_idx > current_page:
            c.showPage()
            current_page = page_idx

        lx = MARGIN_X + col * (LABEL_W + GAP_X)
        ly = (PAGE_H - MARGIN_Y
              - (row_on_pg + 1) * LABEL_H
              - row_on_pg * GAP_Y)

        draw_label(c, lx, ly, order, date_str, logo)
        print(f'  ✓ [{idx+1:>3}/{len(orders)}]  {order["student"]:<30}'
              f'  {order["school"][:28]:<28}  {order["classroom"]}')

    c.save()


# ─────────────────────────────────────────────────────────────────
#  MAIN
# ─────────────────────────────────────────────────────────────────
def main():
    print()
    print('═' * 62)
    print('   THE LUNCH LADY — Label Generator')
    print('═' * 62)

    excel_path = find_excel()
    if excel_path is None:
        print('\n❌  No Excel file found.')
        print('    Make sure Lunch Lady Template.xlsx is placed in the root directory folder.')
        sys.exit(1)   # ← exits cleanly; VBA reads error code 1

    # Check logo state
    has_logo_str = LOGO_BASE64.strip() and "PASTE_YOUR_BASE64_TEXT_HERE" not in LOGO_BASE64
    logo_status = ("Found (File) ✓" if LOGO_FILE.exists()
                   else ("Found (Embedded String) ✓" if has_logo_str
                         else "NOT FOUND — labels will skip logo"))

    print(f'\n📂  Excel   : {excel_path.name}')
    print(f'🖼  Logo    : {logo_status}')
    print(f'📁  Output  : {OUTPUT_DIR.name}/')

    print('\n📊  Reading Daily_Packing sheet...')
    try:
        svc_date, orders = load_orders(excel_path)
    except Exception as e:
        print(f'\n❌  Error reading Excel file:\n    {e}')
        sys.exit(1)   # ← exits cleanly; VBA reads error code 1

    if not orders:
        print('\n⚠   No orders found in the Daily_Packing sheet.')
        print('    Make sure the date in cell C1 has matching data in All Orders.')
        sys.exit(1)   # ← exits cleanly; VBA reads error code 1

    day_str = str(svc_date.day)
    date_nice = svc_date.strftime('%B ') + day_str + svc_date.strftime(', %Y')
    print(f'📅  Date    : {date_nice}')
    print(f'🎒  Students: {len(orders)}')
    print(f'📄  Pages   : ~{((len(orders) + COLS - 1) // COLS + ROWS_PP - 1) // ROWS_PP}')

    OUTPUT_DIR.mkdir(exist_ok=True)
    out_pdf = OUTPUT_DIR / f'Labels_{svc_date.strftime("%Y-%m-%d")}.pdf'

    print(f'\n🖨  Generating labels...\n')

    try:
        generate_pdf(orders, svc_date, out_pdf)
    except Exception as e:
        import traceback
        print(f'\n❌  Error generating PDF:\n    {e}')
        traceback.print_exc()
        sys.exit(1)   # ← exits cleanly; VBA reads error code 1

    print()
    print('═' * 62)
    print(f'✅  Done!  {len(orders)} labels saved to:')
    print(f'    {out_pdf.relative_to(ROOT_DIR) if out_pdf.is_relative_to(ROOT_DIR) else out_pdf}')
    print()
    print('   → Open PDF and print on MUNBYN 4"×2" thermal labels')
    print('   → Labels sorted: School → Teacher → Student')
    print('═' * 62)
    # NO input() here — script exits naturally, VBA gets error code 0 = success


if __name__ == '__main__':
    main()